309→                />
310→                <View style={styles.commentMeta}>
311→                  <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
312→                    {comment.users?.name || 'User'}
313→                  </Text>
314→                  <Text style={[styles.commentTime, {color: colors.textFaint}]}>
315→                    {formatRelativeDate(comment.created_at)}
316→                  </Text>
317→                </View>
318→              </View>
319→              <Text style={[styles.commentBody, {color: colors.textSecondary}]}>
320→                {comment.comment || ''}
321→              </Text>
322→            </View>
323→          ))
324→        )}
325→
326→        {/* Comment input */}
327→        {token ? (
328→          <View style={styles.commentInputRow}>
329→            <TextInput
330→              value={commentInput}
331→              onChangeText={setCommentInput}
332→              placeholder="Write a comment..."
333→              placeholderTextColor={colors.textFaint}
334→              style={[
335→                styles.commentInput,
336→                {
337→                  backgroundColor: colors.bgSecondary,
338→                  borderColor: colors.borderCard,
339→                  color: colors.textPrimary,
340→                },
341→              ]}
342→              maxLength={200}
343→              multiline
344→            />
345→            <PrimaryButton
