 32→const formatRelativeDate = (value?: string): string => {
 33→  if (!value) return '';
 34→  const date = new Date(value);
 35→  if (Number.isNaN(date.getTime())) return value;
 36→  const diff = Date.now() - date.getTime();
 37→  const mins = Math.floor(diff / 60000);
 38→  if (mins < 1) return 'Just now';
 39→  if (mins < 60) return `${mins}m`;
 40→  const hours = Math.floor(mins / 60);
 41→  if (hours < 24) return `${hours}h`;
 42→  const days = Math.floor(hours / 24);
 43→  if (days < 7) return `${days}d`;
 44→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric'});
 45→};
